A generator seems like a better alternative because it specifically exists to automatically generate the `enum` for you (including the flattening part).
```rust
            enum Iter<T1, T2, T3> {
                I1(T1),
                I2(T2),
                I3(T3),
            }
            impl<
                T1: Iterator<Item = DefIndex>,
                T2: Iterator<Item = DefIndex>,
                T3: Iterator<Item = DefIndex>,
            > Iterator for Iter<T1, T2, T3>
            {
                type Item = DefIndex;
                fn next(&mut self) -> Option<Self::Item> {
                    match self {
                        Iter::I1(i1) => i1.next(),
                        Iter::I2(i2) => i2.next(),
                        Iter::I3(i3) => i3.next(),
                    }
                }
            }

            record!(self.tables.children[def_id] <- {
                md.item_ids.iter().flat_map(|item_id| match tcx.hir().item(*item_id).kind {
                    hir::ItemKind::ForeignMod { items, .. } => {
                        Iter::I1(items.iter().map(|fi_ref| fi_ref.id.def_id.local_def_index))
                    }
                    hir::ItemKind::ExternCrate(..) => Iter::I2(iter::empty()),
                    _ if tcx.def_key(item_id.def_id.to_def_id()).get_opt_name().is_some() => {
                        Iter::I3(iter::once(item_id.def_id.local_def_index))
                    }
                    _ => Iter::I2(iter::empty()),
                })
            });
