pub trait TryCaptureGeneric<T> {
    fn try_capture(&self, to: &mut Capture<T>);
}

impl<T> TryCaptureGeneric<T> for &Wrapper<&T> {
    #[inline]
    fn try_capture(&self, to: &mut Capture<T>) {
        *to = Capture::NoCopy;
    }
}

